/**
 * UndoRedoManager — Command Pattern for Editor Operations
 *
 * Provides a framework-agnostic undo/redo system using the Command Pattern.
 * Each operation is encapsulated as a Command with execute() and undo() methods.
 *
 * @module lib/editor/undo-redo
 */

import { logger } from '@/lib/logger';

// ============================================================================
// Types & Interfaces
// ============================================================================

/** Base interface for all undoable commands */
export interface UndoableCommand<TState = unknown> {
  /** Unique identifier for this command instance */
  readonly id: string;
  /** Human-readable description for UI display */
  readonly description: string;
  /** Command type for grouping/filtering */
  readonly type: CommandType;
  /** Timestamp when command was created */
  readonly timestamp: number;
  /** Execute the command (apply changes to state) */
  execute(state: TState): TState;
  /** Reverse the command (undo changes to state) */
  undo(state: TState): TState;
}

/** Available command types */
export type CommandType =
  | 'slide:add'
  | 'slide:remove'
  | 'slide:reorder'
  | 'slide:duplicate'
  | 'element:add'
  | 'element:remove'
  | 'element:move'
  | 'element:resize'
  | 'element:update'
  | 'element:style'
  | 'text:edit'
  | 'scene:update'
  | 'batch'
  | 'custom';

/** Options for creating the UndoRedoManager */
export interface UndoRedoManagerOptions {
  /** Maximum number of undo steps to keep (default: 50) */
  maxHistorySize?: number;
  /** Callback fired after any undo/redo/execute operation */
  onChange?: (state: UndoRedoState) => void;
}

/** Snapshot of the undo/redo state for external consumers */
export interface UndoRedoState {
  canUndo: boolean;
  canRedo: boolean;
  undoDescription: string | null;
  redoDescription: string | null;
  historySize: number;
  undoStackSize: number;
  redoStackSize: number;
}

// ============================================================================
// UndoRedoManager Class
// ============================================================================

/**
 * Manages an undo/redo stack using the Command Pattern.
 *
 * Usage:
 * ```ts
 * const manager = new UndoRedoManager<EditorState>({ maxHistorySize: 100 });
 * const newState = manager.execute(someCommand, currentState);
 * const undoneState = manager.undo(newState);
 * const redoneState = manager.redo(undoneState);
 * ```
 */
export class UndoRedoManager<TState = unknown> {
  private undoStack: UndoableCommand<TState>[] = [];
  private redoStack: UndoableCommand<TState>[] = [];
  private readonly maxHistorySize: number;
  private readonly onChange?: (state: UndoRedoState) => void;

  constructor(options: UndoRedoManagerOptions = {}) {
    this.maxHistorySize = options.maxHistorySize ?? 50;
    this.onChange = options.onChange;
  }

  /**
   * Execute a command and push it onto the undo stack.
   * Clears the redo stack (branching).
   */
  execute(command: UndoableCommand<TState>, currentState: TState): TState {
    const newState = command.execute(currentState);

    this.undoStack.push(command);

    // Trim undo stack if it exceeds max size
    if (this.undoStack.length > this.maxHistorySize) {
      this.undoStack = this.undoStack.slice(
        this.undoStack.length - this.maxHistorySize,
      );
    }

    // Clear redo stack on new action (standard undo/redo behavior)
    this.redoStack = [];

    logger.debug('UndoRedoManager: executed command', {
      type: command.type,
      description: command.description,
      undoStackSize: this.undoStack.length,
    });

    this.notifyChange();
    return newState;
  }

  /**
   * Undo the last command. Returns the previous state.
   * Returns currentState unchanged if nothing to undo.
   */
  undo(currentState: TState): TState {
    const command = this.undoStack.pop();
    if (!command) return currentState;

    const previousState = command.undo(currentState);
    this.redoStack.push(command);

    logger.debug('UndoRedoManager: undo', {
      type: command.type,
      description: command.description,
    });

    this.notifyChange();
    return previousState;
  }

  /**
   * Redo the last undone command. Returns the new state.
   * Returns currentState unchanged if nothing to redo.
   */
  redo(currentState: TState): TState {
    const command = this.redoStack.pop();
    if (!command) return currentState;

    const newState = command.execute(currentState);
    this.undoStack.push(command);

    logger.debug('UndoRedoManager: redo', {
      type: command.type,
      description: command.description,
    });

    this.notifyChange();
    return newState;
  }

  /** Clear all undo/redo history */
  clear(): void {
    this.undoStack = [];
    this.redoStack = [];
    this.notifyChange();
  }

  /** Get current undo/redo state info */
  getState(): UndoRedoState {
    return {
      canUndo: this.undoStack.length > 0,
      canRedo: this.redoStack.length > 0,
      undoDescription:
        this.undoStack.length > 0
          ? this.undoStack[this.undoStack.length - 1].description
          : null,
      redoDescription:
        this.redoStack.length > 0
          ? this.redoStack[this.redoStack.length - 1].description
          : null,
      historySize: this.undoStack.length + this.redoStack.length,
      undoStackSize: this.undoStack.length,
      redoStackSize: this.redoStack.length,
    };
  }

  /** Get the full undo history (for debugging/UI) */
  getUndoHistory(): ReadonlyArray<{ type: CommandType; description: string; timestamp: number }> {
    return this.undoStack.map((cmd) => ({
      type: cmd.type,
      description: cmd.description,
      timestamp: cmd.timestamp,
    }));
  }

  private notifyChange(): void {
    this.onChange?.(this.getState());
  }
}

// ============================================================================
// Command Factories
// ============================================================================

let commandCounter = 0;

/** Generate a unique command ID */
function generateCommandId(type: CommandType): string {
  commandCounter++;
  return `${type}-${commandCounter}-${Date.now()}`;
}

/**
 * Create a generic undoable command from execute/undo functions.
 * This is the simplest way to create a command.
 */
export function createCommand<TState>(
  type: CommandType,
  description: string,
  executeFn: (state: TState) => TState,
  undoFn: (state: TState) => TState,
): UndoableCommand<TState> {
  return {
    id: generateCommandId(type),
    description,
    type,
    timestamp: Date.now(),
    execute: executeFn,
    undo: undoFn,
  };
}

// ============================================================================
// Slide Commands
// ============================================================================

interface SlideItem {
  id: string;
  [key: string]: unknown;
}

interface StateWithSlides {
  slides: SlideItem[];
  [key: string]: unknown;
}

/**
 * Command: Add a new slide at a specific position
 */
export function addSlideCommand<TState extends StateWithSlides>(
  slide: SlideItem,
  atIndex?: number,
): UndoableCommand<TState> {
  const insertAt = atIndex;

  return createCommand<TState>(
    'slide:add',
    `Adicionar slide "${slide.id}"`,
    (state) => {
      const slides = [...state.slides];
      const idx = insertAt ?? slides.length;
      slides.splice(idx, 0, slide);
      return { ...state, slides };
    },
    (state) => {
      const slides = state.slides.filter((s) => s.id !== slide.id);
      return { ...state, slides };
    },
  );
}

/**
 * Command: Remove a slide by ID
 */
export function removeSlideCommand<TState extends StateWithSlides>(
  slideId: string,
): UndoableCommand<TState> {
  let removedSlide: SlideItem | null = null;
  let removedIndex = -1;

  return createCommand<TState>(
    'slide:remove',
    `Remover slide "${slideId}"`,
    (state) => {
      removedIndex = state.slides.findIndex((s) => s.id === slideId);
      removedSlide = removedIndex >= 0 ? state.slides[removedIndex] : null;
      const slides = state.slides.filter((s) => s.id !== slideId);
      return { ...state, slides };
    },
    (state) => {
      if (!removedSlide) return state;
      const slides = [...state.slides];
      slides.splice(removedIndex, 0, removedSlide);
      return { ...state, slides };
    },
  );
}

/**
 * Command: Reorder slides (move slide from one index to another)
 */
export function reorderSlidesCommand<TState extends StateWithSlides>(
  fromIndex: number,
  toIndex: number,
): UndoableCommand<TState> {
  return createCommand<TState>(
    'slide:reorder',
    `Reordenar slide de posição ${fromIndex + 1} para ${toIndex + 1}`,
    (state) => {
      const slides = [...state.slides];
      const [moved] = slides.splice(fromIndex, 1);
      slides.splice(toIndex, 0, moved);
      return { ...state, slides };
    },
    (state) => {
      const slides = [...state.slides];
      const [moved] = slides.splice(toIndex, 1);
      slides.splice(fromIndex, 0, moved);
      return { ...state, slides };
    },
  );
}

// ============================================================================
// Element Commands
// ============================================================================

interface ElementItem {
  id: string;
  [key: string]: unknown;
}

interface StateWithElements {
  elements: ElementItem[];
  [key: string]: unknown;
}

/**
 * Command: Add a new element to the canvas
 */
export function addElementCommand<TState extends StateWithElements>(
  element: ElementItem,
): UndoableCommand<TState> {
  return createCommand<TState>(
    'element:add',
    `Adicionar elemento "${element.id}"`,
    (state) => ({
      ...state,
      elements: [...state.elements, element],
    }),
    (state) => ({
      ...state,
      elements: state.elements.filter((e) => e.id !== element.id),
    }),
  );
}

/**
 * Command: Remove an element by ID
 */
export function removeElementCommand<TState extends StateWithElements>(
  elementId: string,
): UndoableCommand<TState> {
  let removedElement: ElementItem | null = null;
  let removedIndex = -1;

  return createCommand<TState>(
    'element:remove',
    `Remover elemento "${elementId}"`,
    (state) => {
      removedIndex = state.elements.findIndex((e) => e.id === elementId);
      removedElement = removedIndex >= 0 ? state.elements[removedIndex] : null;
      return {
        ...state,
        elements: state.elements.filter((e) => e.id !== elementId),
      };
    },
    (state) => {
      if (!removedElement) return state;
      const elements = [...state.elements];
      elements.splice(removedIndex, 0, removedElement);
      return { ...state, elements };
    },
  );
}

/**
 * Command: Move an element to a new position
 */
export function moveElementCommand<TState extends StateWithElements>(
  elementId: string,
  fromX: number,
  fromY: number,
  toX: number,
  toY: number,
): UndoableCommand<TState> {
  return createCommand<TState>(
    'element:move',
    `Mover elemento "${elementId}"`,
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId ? { ...e, x: toX, y: toY } : e,
      ),
    }),
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId ? { ...e, x: fromX, y: fromY } : e,
      ),
    }),
  );
}

/**
 * Command: Resize an element
 */
export function resizeElementCommand<TState extends StateWithElements>(
  elementId: string,
  fromSize: { width: number; height: number },
  toSize: { width: number; height: number },
): UndoableCommand<TState> {
  return createCommand<TState>(
    'element:resize',
    `Redimensionar elemento "${elementId}"`,
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId
          ? { ...e, width: toSize.width, height: toSize.height }
          : e,
      ),
    }),
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId
          ? { ...e, width: fromSize.width, height: fromSize.height }
          : e,
      ),
    }),
  );
}

// ============================================================================
// Text Commands
// ============================================================================

/**
 * Command: Edit text content of an element
 */
export function editTextCommand<TState extends StateWithElements>(
  elementId: string,
  oldText: string,
  newText: string,
): UndoableCommand<TState> {
  return createCommand<TState>(
    'text:edit',
    `Editar texto de "${elementId}"`,
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId ? { ...e, text: newText, content: newText } : e,
      ),
    }),
    (state) => ({
      ...state,
      elements: state.elements.map((e) =>
        e.id === elementId ? { ...e, text: oldText, content: oldText } : e,
      ),
    }),
  );
}

// ============================================================================
// Batch Command
// ============================================================================

/**
 * Command: Execute multiple commands as a single undoable action
 */
export function batchCommand<TState>(
  description: string,
  commands: UndoableCommand<TState>[],
): UndoableCommand<TState> {
  return createCommand<TState>(
    'batch',
    description,
    (state) => commands.reduce((s, cmd) => cmd.execute(s), state),
    (state) =>
      [...commands].reverse().reduce((s, cmd) => cmd.undo(s), state),
  );
}

// ============================================================================
// Exports
// ============================================================================

export type {
  SlideItem,
  StateWithSlides,
  ElementItem,
  StateWithElements,
};
